	public bool RequirePerServiceCallChatHistoryPersistence { get; set; }

	/// <summary>
	/// Creates a new instance of <see cref="T:Microsoft.Agents.AI.ChatClientAgentOptions" /> with the same values as this instance.
	/// </summary>
	public ChatClientAgentOptions Clone()
	{
		ChatClientAgentOptions obj = new ChatClientAgentOptions
		{
			Id = Id,
			Name = Name,
			Description = Description
		};
		ChatOptions? chatOptions = ChatOptions;
		obj.ChatOptions = ((chatOptions != null) ? chatOptions.Clone() : null);
		obj.ChatHistoryProvider = ChatHistoryProvider;
		obj.AIContextProviders = ((AIContextProviders == null) ? null : new List<AIContextProvider>(AIContextProviders));
		obj.UseProvidedChatClientAsIs = UseProvidedChatClientAsIs;
		obj.ClearOnChatHistoryProviderConflict = ClearOnChatHistoryProviderConflict;
		obj.WarnOnChatHistoryProviderConflict = WarnOnChatHistoryProviderConflict;
		obj.ThrowOnChatHistoryProviderConflict = ThrowOnChatHistoryProviderConflict;
		obj.RequirePerServiceCallChatHistoryPersistence = RequirePerServiceCallChatHistoryPersistence;
		return obj;
	}
}
