using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Provides an in-memory note-taking tool for the research agent.
/// </summary>
public sealed class NoteService
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("The content of the note to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to review findings before summarizing.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note #{i + 1} ---\n{n}"));
    }
}

using System.ComponentModel;
