namespace ResearchAgent;

/// <summary>
/// Provides a web search tool backed by DuckDuckGo.
/// </summary>
public sealed partial class WebSearchService : IDisposable
{
    private readonly HttpClient _httpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (compatible)" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information about a query. Returns up to 5 result snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = HttpUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var html = await _httpClient.GetStringAsync(url, cancellationToken);
            var snippets = ExtractSnippets(html);

            if (snippets.Count == 0)
            {
                return $"No results found for: {query}";
            }

            return string.Join("\n\n", snippets.Take(5)
                .Select((s, i) => $"[Result {i + 1}]\n{s}"));
        }
        catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ExtractSnippets(string html)
    {
        var results = new List<string>();

        var titles = TitleRegex().Matches(html);
        var snippets = SnippetRegex().Matches(html);

        for (int i = 0; i < Math.Min(titles.Count, snippets.Count); i++)
        {
            var title = StripHtml(titles[i].Groups[1].Value).Trim();
            var snippet = StripHtml(snippets[i].Groups[1].Value).Trim();

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(snippet))
            {
                results.Add($"{title}\n{snippet}");
            }
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, "");
        return HttpUtility.HtmlDecode(text);
    }

    public void Dispose() => _httpClient.Dispose();

