+using var searchService = new WebSearchService();
+var noteService = new NoteService();
+
+var tools = new List<AITool>
+{
+    AIFunctionFactory.Create(searchService.SearchWebAsync),
+    AIFunctionFactory.Create(noteService.SaveNote),
+    AIFunctionFactory.Create(noteService.GetNotes),
+};
+
+// --- Create agent ---
+const string instructions = """
+    You are a research agent. Your job is to thoroughly research a topic using the
+    available tools, then produce a well-structured summary.
+
+    Follow this workflow:
+    1. Search the web for the topic to get an overview.
+    2. Save the most important findings as notes.
+    3. Search for additional subtopics, different perspectives, or recent developments.
+    4. Save additional findings as notes.
+    5. Once you have gathered enough information, retrieve your notes and produce a
+       comprehensive, well-organized summary with key facts and sources.
+
+    Always save key findings as notes before writing your final summary.
+    """;
+
+var agent = new ChatClientAgent(
+    innerClient,
+    instructions: instructions,
+    name: "ResearchAgent",
+    description: "An agent that researches topics using web search and note-taking.",
+    tools: tools);
+
+// --- Get topic from user ---
+Console.Write("Enter a research topic: ");
+var topic = Console.ReadLine()?.Trim();
+
+if (string.IsNullOrEmpty(topic))
+{
+    Console.WriteLine("No topic provided. Exiting.");
+    return;
+}
+
+Console.WriteLine($"\n🔍 Researching: {topic}\n");
+
+// --- Run the agent with streaming output ---
+var session = new ChatClientAgentSession();
+var runOptions = new ChatClientAgentRunOptions(
+    new ChatOptions
+    {
+        Temperature = 0f,
+        MaxOutputTokens = 2048,
+    });
+
+await foreach (var update in agent.RunStreamingAsync(
+    $"Research the following topic and provide a comprehensive summary: {topic}",
+    session,
+    runOptions))
+{
+    if (update.Text is { Length: > 0 } text)
+    {
+        Console.Write(text);
+    }
+}
+
+Console.WriteLine();
+Console.WriteLine("\n✅ Research complete.");
